"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import styles from "./profile.module.css";
import { useToast } from "@/context/ToastContext";

type Props = {
    initialName: string;
    initialImage: string;
    initialTitle: string;
    initialShortDescription: string;
    initialLongBio: string;
    initialSpecialties: string[];
    initialLanguages: string[];
    initialYearsOfExperience: number;
    isComplete: boolean;
};

export default function CoachProfileForm(props: Props) {
    const router = useRouter();
    const { showToast } = useToast();

    const [name, setName] = useState(props.initialName);
    const [image, setImage] = useState(props.initialImage);
    const [title, setTitle] = useState(props.initialTitle);
    const [shortDescription, setShortDescription] = useState(
        props.initialShortDescription
    );
    const [longBio, setLongBio] = useState(props.initialLongBio);
    const [specialties, setSpecialties] = useState(
        props.initialSpecialties.join(", ")
    );
    const [languages, setLanguages] = useState(props.initialLanguages.join(", "));
    const [yearsOfExperience, setYearsOfExperience] = useState(
        props.initialYearsOfExperience > 0
            ? String(props.initialYearsOfExperience)
            : ""
    );

    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false);

    const initials =
        name
            .split(" ")
            .filter(Boolean)
            .slice(0, 2)
            .map((part) => part[0]?.toUpperCase())
            .join("") || "C";

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);
        setSuccess(null);

        if (!image.trim()) {
            setError("Lägg till en profilbild");
            return;
        }

        if (!name.trim()) {
            setError("Fyll i ditt namn");
            return;
        }

        if (!shortDescription.trim()) {
            setError("Skriv en kort beskrivning");
            return;
        }

        setIsSaving(true);

        try {
            const res = await fetch("/api/coach/profile", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({
                    name,
                    image,
                    shortDescription,
                    title,
                    longBio,
                    specialties,
                    yearsOfExperience,
                    languages,
                }),
            });

            const data = await res.json();

            if (!res.ok) {
                const message = data.error || "Kunde inte spara profilen";
                setError(message);
                showToast(message, "error");
                return;
            }

            setSuccess("Profilen sparades");
            showToast("Profilen sparades", "success");

            setTimeout(() => {
                router.push("/coach/dashboard");
            }, 700);
        } catch (err) {
            const message = "Kunde inte spara profilen";
            setError(message);
            showToast(message, "error");
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <form className={styles.form} onSubmit={handleSubmit}>
            <div className={styles.avatarRow}>
                <div className={styles.avatarPreview} aria-busy={isSaving}>
                    {image ? (
                        <img src={image} alt={name || "Coach"} />
                    ) : (
                        <span>{initials}</span>
                    )}
                    {isSaving && (
                        <div className={styles.avatarOverlay}>
                            <span className="spinner" aria-hidden="true" />
                            <span className={styles.avatarOverlayText}>Sparar...</span>
                        </div>
                    )}
                </div>
                <div className={styles.avatarFields}>
                    <label className={styles.label}>
                        Profilbild
                        <input
                            type="url"
                            className={styles.input}
                            placeholder="Länk till profilbild (https://...)"
                            value={image}
                            onChange={(e) => setImage(e.target.value)}
                        />
                    </label>
                    <p className={styles.helperText}>
                        Klistra in en säker bildlänk för din profil. Du ser en förhandsvisning ovan.
                    </p>
                </div>
            </div>

            <div className={styles.grid}>
                <label className={styles.label}>
                    Namn
                    <input
                        type="text"
                        className={styles.input}
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        placeholder="Ditt fullständiga namn"
                    />
                </label>

                <label className={styles.label}>
                    Titel
                    <input
                        type="text"
                        className={styles.input}
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        placeholder="Till exempel: Samtalscoach, Stresscoach..."
                    />
                </label>
            </div>

            <label className={styles.label}>
                Kort beskrivning
                <textarea
                    className={styles.textarea}
                    value={shortDescription}
                    onChange={(e) => setShortDescription(e.target.value)}
                    placeholder="Beskriv kort vem du är och hur du stöttar dina klienter."
                    rows={3}
                />
            </label>

            <label className={styles.label}>
                Längre presentation (valfritt)
                <textarea
                    className={styles.textarea}
                    value={longBio}
                    onChange={(e) => setLongBio(e.target.value)}
                    placeholder="Här kan du berätta lite mer om din bakgrund, ditt arbetssätt och vad som är viktigt i dina samtal."
                    rows={5}
                />
            </label>

            <div className={styles.grid}>
                <label className={styles.label}>
                    Specialiseringar (valfritt)
                    <input
                        type="text"
                        className={styles.input}
                        value={specialties}
                        onChange={(e) => setSpecialties(e.target.value)}
                        placeholder="Till exempel: stress, utmattning, relationer (kommaseparerat)"
                    />
                </label>

                <label className={styles.label}>
                    Språk (valfritt)
                    <input
                        type="text"
                        className={styles.input}
                        value={languages}
                        onChange={(e) => setLanguages(e.target.value)}
                        placeholder="Till exempel: Svenska, Engelska"
                    />
                </label>
            </div>

            <label className={styles.label}>
                År av erfarenhet (valfritt)
                <input
                    type="number"
                    min={0}
                    className={styles.input}
                    value={yearsOfExperience}
                    onChange={(e) => setYearsOfExperience(e.target.value)}
                    placeholder="Till exempel: 5"
                />
            </label>

            {error && <p className={styles.error}>{error}</p>}
            {success && <p className={styles.success}>{success}</p>}

            <div className={styles.actions}>
                <button
                    type="submit"
                    className={styles.primaryButton}
                    disabled={isSaving}
                    aria-busy={isSaving}
                    aria-live="polite"
                >
                    {isSaving && <span className="spinner" style={{ marginRight: 8 }} aria-hidden="true" />}
                    {isSaving ? "Sparar..." : props.isComplete ? "Uppdatera profil" : "Spara profil"}
                </button>
            </div>
        </form>
    );
}

